// Time:  O(n * m * logn(n * m))
// Space: O(n * m)

// dijkstra's algorithm
class Solution {
public:
    int minTimeToReach(vector<vector<int>>& moveTime) {
        static const int INF = numeric_limits<int>::max();
        static const vector<pair<int, int>> DIRECTIONS = {{1, 0}, {0, 1}, {-1, 0}, {0, -1}};

        const auto& dijkstra = [&](const pair<int, int>& start, const pair<int, int>& target) {
            vector<vector<int>> dist(size(moveTime), vector<int>(size(moveTime[0]), INF));
            dist[start.first][start.second] = 0;
            priority_queue<tuple<int, int, int>, vector<tuple<int, int, int>>, greater<tuple<int, int, int>>> min_heap;
            min_heap.emplace(dist[start.first][start.second], start.first, start.second);
            while (!empty(min_heap)) {
                const auto [curr, i, j] = min_heap.top(); min_heap.pop();
                if (curr != dist[i][j]) {
                    continue;
                }
                if (pair(i, j) == target) {
                    break;
                }
                for (const auto& [di, dj] : DIRECTIONS) {
                    const int ni = i + di, nj = j + dj;
                    const int c = (i + j) % 2 + 1;
                    if (!(0 <= ni && ni < size(moveTime) && 0 <= nj && nj < size(moveTime[0]) && dist[ni][nj] > max(moveTime[ni][nj], curr) + c)) {
                        continue;
                    }
                    dist[ni][nj] = max(moveTime[ni][nj], curr) + c;
                    min_heap.emplace(dist[ni][nj], ni, nj);
                }
            }
            return dist[target.first][target.second];
        };

        return dijkstra({0, 0}, {size(moveTime) - 1, size(moveTime[0]) - 1});
    }
};

# Time:  O(n * m * logn(n * m))
# Space: O(n * m)

import heapq


# dijkstra's algorithm
class Solution(object):
    def minTimeToReach(self, moveTime):
        """
        :type moveTime: List[List[int]]
        :rtype: int
        """
        def dijkstra(start, target):
            DIRECTIONS = [(1, 0), (0, 1), (-1, 0), (0, -1)]
            dist = [[float("inf")]*len(moveTime[0]) for _ in xrange(len(moveTime))]
            dist[start[0]][start[1]] = 0
            min_heap = [(dist[start[0]][start[1]], start[0], start[1])]
            while min_heap:
                curr, i, j = heapq.heappop(min_heap)
                if curr != dist[i][j]:
                    continue
                if (i, j) == target:
                    break
                for di, dj in DIRECTIONS:
                    ni, nj = i+di, j+dj
                    c = (i+j)%2+1
                    if not (0 <= ni < len(moveTime) and 0 <= nj < len(moveTime[0]) and dist[ni][nj] > max(moveTime[ni][nj], curr)+c):
                        continue
                    dist[ni][nj] = max(moveTime[ni][nj], curr)+c
                    heapq.heappush(min_heap, (dist[ni][nj], ni, nj))
            return dist[target[0]][target[1]]

        return dijkstra((0, 0), (len(moveTime)-1, len(moveTime[0])-1))
